d = {}
d[(1, 2)] = "ok"     # tuple is hashable -> fine

try:
    d[[1, 2]] = "nope"   # list is mutable -> unhashable
except TypeError as e:
    print(e)             # unhashable type: 'list'

words = "a b a c b a".split()

counts = {}
for w in words:
    counts[w] = counts.get(w, 0) + 1   # safe default
print(counts)               # {'a': 3, 'b': 2, 'c': 1}

for key, val in counts.items():        # iterate pairs
    print(key, "->", val)

a = {1, 2, 3, 4}
b = {3, 4, 5, 6}

print(a | b)    # union        {1,2,3,4,5,6}
print(a & b)    # intersection {3, 4}
print(a - b)    # difference   {1, 2}
print(a ^ b)    # symmetric    {1, 2, 5, 6}

print(set([1, 1, 2, 2, 3]))   # dedup -> {1, 2, 3}
